head.script:
//-------------------------------------------------------------------------
// 화면 로딩
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // 세션정보 가져오기
    scwin.memInfo = $c.data.getMemInfo();
    scwin.lobranCd = scwin.memInfo.lobranCd; 
    scwin.loginId = scwin.memInfo.userId;

    //오늘일자 세팅
    scwin.sDate = $c.date.getServerDateTime();
    scwin.nextDt = $c.date.addDate(scwin.sDate, 1);
    scwin.beforeDt = $c.date.addDate(scwin.sDate, -1);

    //다른화면에서 넘어오는 경우
    scwin.params = $c.data.getParameter();
    scwin.odrNo = scwin.params.odrNo == null ? "" : scwin.params.odrNo;			//오더번호
    scwin.odrKndCd = scwin.params.odrKndCd == null ? "" : scwin.params.odrKndCd;		//오더종류
    scwin.type = scwin.params.type == null ? "" : scwin.params.type;			//type
    scwin.linkPage = scwin.params.linkPage == null ? "" : scwin.params.linkPage;		//링크페이지 종류
    scwin.odrCopy = scwin.params.odrCopy == null ? "" : scwin.params.odrCopy;		//웹오더요청번호

    scwin.odrKndCd = "";   //오더종류코드
    scwin.impExpClsCd = "";   //수출입내수구분코드
    scwin.statusFlag = "";   //수정/등록 Flag(C:Regist, U:Update)
    scwin.mgntTrgtClntYn = 0;    //거래처 관리대상여부
    scwin.retrieveYn = "N";  //조회여부
    scwin.odrCtrlClsCd = "";   //TS구분 -01적하,02비적하
    scwin.excelUploadYn = 0;    //EXCEL UPLOAD (C3) 여부
    scwin.selfClsCd = "";   //자가구분코드 - 자가구분콤보 onSelChange이벤트에서 값 세팅
    scwin.sellYnCd = "";   //매출여부
    scwin.offdock_yn = 1;	  //default offdock처리
    scwin.callBackNoNeed = "N";

    tbl_c7Format.hide();
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {

    try {
        const results = await Promise.all([
            scwin.loadCommonCodePromise(),
            scwin.loadDsCommonUtilPromise(),
            scwin.loadGauceUtilPromise()
        ]);
    } catch (error) {
        //console.error("공통코드 조회 중 오류 발생", error)
    }

    await scwin.f_retrieveGridLookup();
    scwin.f_set("INIT", "CREATE");

    if (scwin.linkPage == "odrList") {

        ed_odrNo.setValue(scwin.odrNo);

        await scwin.f_retrieve();

        if (scwin.odrCopy == "copy") {
            scwin.set_copy();
        }
    }

    tr_vanTerm.hide();

    ica_wrkStDt.setValue(scwin.sDate);
    ica_wrkEndDt.setValue(scwin.sDate);

    scwin.f_c5c6EnDisableSet();
    scwin.f_setSellAndBilgDept();

    rd_sellYn.setValue("1");
    scwin.f_setLineCd();

    ed_blNo.hide();
    btn_blNo.hide();

    gr_cntrInfo.setReadOnly("column", "fullEmptyClsCd", false);
};

scwin.loadCommonCodePromise = function () {
    const codeOptions = [{ grpCd: "SD165", compID: "gr_cntrInfo:cntrWrkClsCd" }];

    // 조건에 따른 UI 및 옵션 분기
    if (scwin.lobranCd == "4AA") {
        txt_onPicTitle.setValue("입고구분");
        ed_onPicNm.unbindRef();
        ed_onPicNm.hide();
        codeOptions.push({ grpCd: "SD401", compID: "lc_time" });
    } else {
        txt_onPicTitle.setValue("상차담당");
        lc_time.unbindRef();
        lc_time.hide();
    }

    // Promise 반환
    return new Promise((resolve) => {
        $c.data.setCommonCode(codeOptions, function () {
            resolve(true);
        });
    });
};

scwin.loadDsCommonUtilPromise = function () {
    const listOptions = [
        {
            compID: "lc_selfClsCd",
            method: "getCodeList",
            param1: "SD114",
            param2: 1,
            param3: DsConstants.ODR_CNTR,
            outputFields: ["CD", "CD_NM"]
        },
        {
            compID: "lc_selfClsCd",
            method: "getCodeList",
            param1: "SD114",
            param2: 1,
            param3: DsConstants.ODR_ALL,
            outputFields: ["CD", "CD_NM"]
        }
    ];

    // Promise 반환
    return new Promise((resolve) => {
        $c.data.setDsCommonUtil(listOptions, function () {
            //lc_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS);
            let dataListComp = $p.getComponentById(lc_selfClsCd.getDataListInfo().id);
            let list = dataListComp.getAllJSON();
            const lastItem = list.pop();
            list.splice(1, 0, lastItem);

            dataListComp.setJSON(list);
            resolve(true);
        });
    });
};

scwin.loadGauceUtilPromise = function () {
    const comboOptions = [
        {
            method: "getCodeList",
            param1: "SD125",
            param2: 1,
            param3: "1",
            compID: "lc_odrClsCd"
        }
    ];

    // Promise 반환
    return new Promise((resolve) => {
        $c.data.setGauceUtil(comboOptions, function () {
            resolve(true);
        });
    });
};


//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_fieldClear = function () {
    ////console.log("scwin.f_fieldClear");
    $c.gus.cfInitObjects(tbl_search);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_retrieve = async function () {
    scwin.first_YN = 0;
    let chkVal = await $c.gus.cfValidate([tbl_search], null, true);
    if (!chkVal) {
        return;
    }
    scwin.retrieveYn = "Y";
    scwin.f_clearDataSet();
    scwin.mgntTrgtClntYn = 0;

    scwin.hid_chkMode = "";
    ds_cndOdrNo.setCellData(0, "odrNo", ed_odrNo.getValue());

    sbm_retrieve.userData1="noError";
    let rtn = await $c.sbm.execute(sbm_retrieve);
    await scwin.sbm_retrieve_submitdone(rtn);
}

//공통팝업 열기
scwin.f_openCommonPopUp = function (gubun1, gubun2, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    return new Promise(async function (resolve, reject) {

        let pCode = "";
        let pWhere = "";
        let pWtitleSearch = "";
        let pSelectId = "";

        // 공통 콜백 처리 함수 
        var handleCallback = async function (callbackFn, data) {
            try {
                if (callbackFn) {
                    await callbackFn(data); // 기존 async callBack 함수 실행 완료 대기
                }
                resolve(data); // Promise 완료 및 데이터 반환
            } catch (e) {
                //console.error("Popup Callback Error:", e);
                reject(e); // 에러 발생 시 처리
            }
        };

        switch (gubun1) {
            case 1: //계약거래처 팝업
                if (gubun2 == "CTRT") { //계약거래처
                    pCode = ed_ctrtClntNo.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        lc_reqClntNm.setSelectedIndex(-1);
                    }
                    pWtitleSearch = "계약 거래처,거래처코드/명";
                    pWhere = ",CTRT,CTRT";

                    udc_ctrtClntNo.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackClntCtrt, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        '9',
                        "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,",
                        '100,100,0,120,100,0,100,100,100,0',
                        "3,10",
                        pWhere,
                        '800',
                        '600',
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );

                } else if (gubun2 == "REQ") { //요청거래처
                    pCode = ed_reqClntNo.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_reqClntNo.hidVal  = pCode;
                        lc_reqClntNm.setSelectedIndex(-1);
                    }
                    pWtitleSearch = "요청 거래처,거래처코드/명";
                    pWhere = ",,CTRT";

                    udc_reqClntNo.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackClntReq, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        '9',
                        "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,",
                        '100,100,0,120,100,0,100,100,100,0',
                        "3,10",
                        pWhere,
                        '800',
                        '600',
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );
                } else if (gubun2 == "BILG") { //청구거래처
                    pCode = ed_bilgClntNo.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_bilgClntNo.hidVal = pCode;
                        lc_bilgClntNm.setSelectedIndex(-1);
                    }
                    pWtitleSearch = "청구 거래처,거래처코드/명";
                    pWhere = ",,CTRT";

                    udc_bilgClntNo.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackClntBilg, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        '9',
                        "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,",
                        '100,100,0,120,100,0,100,100,100,0',
                        "3,10",
                        pWhere,
                        '800',
                        '600',
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );
                }
                break;

            case 2: //매출/청구부서
                //pWhere = "T,J";   // 물류점소구분코드 : LO120 - 팀(T), 지점(A), 사업소(B), CY(C), CFS(F)
                if (gubun2 == "SELL") { //매출부서
                    pCode = ed_sellLodeptCd.getValue().trim();
                    scwin.pNoDataCloseTF = pNoDataCloseTF;
                    if (pNoDataCloseTF == "T") {
                        //ed_sellLodeptCd.hidVal = pCode;
                        ed_sellLodeptNm.setValue("");
                        pWhere = "T,J,,,T,T,1";
                    } else {
                        pWhere = "T,J,,,,T,1";
                    }
                    pWtitleSearch = "매출부서,부서코드/명";

                    udc_sellLodeptCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackSellLodept, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        null,
                        null,
                        null,
                        null,
                        pWhere,
                        null,
                        null,
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );

                } else if (gubun2 == "BILG") { //청구부서
                    pCode = ed_bilgLodeptCd.getValue().trim();
                    scwin.pNoDataCloseTF = pNoDataCloseTF;
                    if (pNoDataCloseTF == "T") {
                        //ed_bilgLodeptCd.hidVal = pCode;
                        ed_bilgLodeptNm.setValue("");
                        pWhere = "T,J,,,T,,,1";
                    } else {
                        pWhere = "T,J,,,,,,1";
                    }
                    pWtitleSearch = "청구부서,부서코드/명";

                    udc_bilgLodeptCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackBilgLodept, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        null,
                        null,
                        null,
                        null,
                        pWhere,
                        null,
                        null,
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );
                }
                break;

            case 3: //Line조회 - Line코드, Line명, 선사코드, 선사코드명
                pCode = ed_lineCd.getValue().trim();
                if (pNoDataCloseTF == "T") {
                    //ed_lineCd.hidVal = pCode;
                    $c.gus.cfInitObjects([ed_lineNm, ed_shpCoClntNm]);
                    $c.gus.cfInitHidVal([ed_lineNm, ed_shpCoClntNm]);
                    ds_odrInfo.setCellData(0, "shpCoClntNo", "");
                    pWhere = "T";
                }
                pWtitleSearch = "LINE,LINE코드/명";
                udc_lineCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackLineInfo, res); },
                    pCode,
                    pCode,
                    pWinCloseTF,
                    null,
                    null,
                    null,
                    null,
                    pWhere,
                    null,
                    null,
                    null,
                    null,
                    null,
                    pAllSearchTF,
                    pWtitleSearch,
                    pNoDataCloseTF,
                    null
                );

                break;

            case 5: //출발/도착 작업장 조회 - 코드/명 가져오기
                if (gubun2 == "DPT") { //출발작업장
                    pCode = ed_dptWrkPlCd.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_dptWrkPlCd.hidVal = pCode;
                        ed_dptWrkPlNm.setValue("");
                    }
                    pWtitleSearch = "출발작업장,작업장코드/명";
                    pSelectId = "retrieveWrkPlInfo_tpro";
                    pWhere = ",,,,,,1";
                    udc_dptWrkPlCd.setSelectId(pSelectId);
                    udc_dptWrkPlCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackWrkDpt, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        null,
                        null,
                        null,
                        null,
                        pWhere,
                        null,
                        null,
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );

                } else if (gubun2 == "ARV") { //도착작업장
                    pCode = ed_arvWrkPlCd.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_arvWrkPlCd.hidVal = pCode;
                        ed_arvWrkPlNm.setValue("");
                    }
                    pWtitleSearch = "도착작업장,작업장코드/명";
                    pSelectId = "retrieveWrkPlInfo_tpro";
                    pWhere = ",,,,,,1";
                    udc_arvWrkPlCd.setSelectId(pSelectId);
                    udc_arvWrkPlCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackWrkArv, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        null,
                        null,
                        null,
                        null,
                        pWhere,
                        null,
                        null,
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );
                } else if (gubun2 == "LDULD") { //상차지
                    pCode = ed_lduldWrkPlCd.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_lduldWrkPlCd.hidVal = pCode;
                        ed_lduldWrkPlNm.setValue("");
                    }
                    pWtitleSearch = "상차지,작업장코드/명";
                    pSelectId = "retrieveWrkPlInfo_tpro";
                    pWhere = ",,,,,,1";
                    udc_lduldWrkPlCd.setSelectId(pSelectId);
                    udc_lduldWrkPlCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackWrkLduld, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        null,
                        null,
                        null,
                        null,
                        pWhere,
                        null,
                        null,
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );
                } else if (gubun2 == "RAILDPT") { //철송출발작업장
                    pCode = ed_railroadDptWrkPlCd.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_railroadDptWrkPlCd.hidVal = pCode;
                        ed_railroadDptWrkPlNm.setValue("");
                    }
                    pWtitleSearch = "철송출발작업장,작업장코드/명";
                    pSelectId = "retrieveWrkPlInfo_tpro";
                    pWhere = ",,,13,,,1";
                    udc_railroadDptWrkPlCd.setSelectId(pSelectId);
                    udc_railroadDptWrkPlCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackRailWrkDpt, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        null,
                        null,
                        null,
                        null,
                        pWhere,
                        null,
                        null,
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );

                } else if (gubun2 == "RAILARV") { //철송도착작업장
                    pCode = ed_railroadArvWrkPlCd.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_railroadArvWrkPlCd.hidVal = pCode;
                        ed_railroadArvWrkPlNm.setValue("");
                    }
                    pWtitleSearch = "철송도착작업장,작업장코드/명";
                    pSelectId = "retrieveWrkPlInfo_tpro";
                    pWhere = ",,,13,,,1";
                    udc_railroadArvWrkPlCd.setSelectId(pSelectId);
                    udc_railroadArvWrkPlCd.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackRailWrkArv, res); },
                        pCode,
                        pCode,
                        pWinCloseTF,
                        null,
                        null,
                        null,
                        null,
                        pWhere,
                        null,
                        null,
                        null,
                        null,
                        null,
                        pAllSearchTF,
                        pWtitleSearch,
                        pNoDataCloseTF,
                        null
                    );
                }
                break;

            case 7: //BL정보 가져오기
                var arrParam = new Array(4);
                arrParam[0] = ed_blNo.getValue().trim(); 	//bl번호
                arrParam[3] = "I"; 				            //수출입구분코드
                arrParam[4] = 0; 						    //bulkYn : 0-컨테이너, 1-벌크
                arrParam[5] = ed_lineCd.getValue().trim(); 	//LINE 코드
                arrParam[6] = DsConstants.YN_NO;	        // TS 오더가 아닌경우로 세팅
                arrParam[7] = "F";						    //다중선택 여부
                arrParam[8] = "F";						    // TS 오더가 아닌경우로 세팅

                let opts = {
                    id: "smpPop"
                    , popupName: "BL조회"
                    , modal: true
                    , type: "browserPopup"
                    , title: "BL조회"
                    , width: 1030
                    , height: 450
                };

                let rtnList = await $c.win.openPopup("/ui/tn/sd/odrmgnt/cntrodrreg/tn_402_01_29p.xml", opts, arrParam);

                if (rtnList != null) {
                    if (rtnList[0] != "N/A") {
                        ed_blNo.setValue(rtnList[3]); // B/L 번호
                        //ed_blNo.hidVal				= rtnList[3];
                        ed_lineCd.setValue(rtnList[4]); //Line코드
                        //ed_lineCd.hidVal			= rtnList[4];

                        if (ds_blInfo.getTotalRwo() > 0) ds_blInfo.removeAll();
                        let insRow = ds_blInfo.insertRow();
                        ds_blInfo.setRowPosition(insRow);
                        ds_blInfo.setCellData(insRow, "mrn", rtnList[0]); //적하목록관리번호(mrn)
                        ds_blInfo.setCellData(insRow, "msn", rtnList[1]); //MSN
                        ds_blInfo.setCellData(insRow, "hsn", rtnList[2]); //HSN
                        ds_blInfo.setCellData(insRow, "blNo", rtnList[3]); //HOUSE_BL번호

                        // 오더 기본정보에 BL정보 셋팅..
                        ds_odrInfo.setCellData(0, "mrn", rtnList[0]); //적하목록관리번호(mrn)
                        ds_odrInfo.setCellData(0, "msn", rtnList[1]); //MSN
                        ds_odrInfo.setCellData(0, "hsn", rtnList[2]); //HSN
                        ds_odrInfo.setCellData(0, "blNo", rtnList[3]); //HOUSE_BL번호

                        //Line명과 선사거래처 가져오기
                        await scwin.f_openCommonPopUp(3, '', 'T', 'F', 'T');

                        //BL번호로 적하목록 BL 품명 정보를 조회한다.
                        scwin.f_retrieveBillOfLadingContainerList();
                    }
                } else {
                    scwin.f_clearDataByBlNo();
                }
                break;

            case 10: //우편번호조회
                if (gubun2 == "DPT_ZIP") { //작업지
                    pCode = ed_dptZip.getValue().trim();
                    if (pNoDataCloseTF == "T") {
                        //ed_dptZip.hidVal = pCode;
                    }
                    pWtitleSearch = "작업지우편번호,우편번호/동이름";
                    pSelectId = "retrieveZipList_tpro";
                    udc_dptZip.setSelectId(pSelectId);
                    udc_dptZip.cfCommonPopUpAsync(function (res) { handleCallback(scwin.callBackZipDpt, res); },
                        pCode,
                        '',
                        pWinCloseTF,
                        null,
