//--------------------------------------------------------
//화면 onLoad시 초기 데이타 setting
//gubun1 : INIT(초기화), RETRIEVE(조회모드), UPDATE(수정모드), COPY(복사모드)
//gubun2 : INIT(초기화), CREATE(신규모드), ODRKNDCD(오더종류 변경되는 경우)
//1.초기화,신규모드,오더종류변경되는 경우 : 오더기본정보 세팅(f_setDefaultValue()참조)
//--------------------------------------------------------
scwin.f_set = async function (gubun1, gubun2) {
    ////console.log(gubun1, gubun2);
    let odrDcsnYn, odrDelYn, odrCompleteYn, autoOdrYn;

    switch (gubun1) {
        case "INIT": //초기화/신규
            if (gubun2 == "INIT") { //초기화모드
                scwin.f_clearDataSet();
                $c.gus.cfDisableKeyData();
                $c.gus.cfDisableAllBtn();
                $c.gus.cfEnableObjects([chk_transhipYn]);
                $c.gus.cfEnableBtnOnly([btn_search, btn_clear]);
                $c.gus.cfDisableObjects([btn_confirmOdr]);
                scwin.f_setActiveImgPopUp("D");         //팝업버튼 비활성화
                gr_cntrInfo.setReadOnly("grid", true);  //그리드 비활성화

                //$c.gus.cfInitHidVal([tbl_odrInfoArea]);
                scwin.statusFlag = "C";     //수정등록 flag
                scwin.mgntTrgtClntYn = 0;   // 계약거래처 관리구분여부 초기화
                lc_odrKndCd.setValue("C5");

            } else if (gubun2 == "CREATE") {//신규모드
                ed_odrNo.setValue("");
                ed_rowMake.setValue("");

                scwin.f_clearDataSet();
                $c.gus.cfEnableKeyData();
                $c.gus.cfDisableKey();
                $c.gus.cfEnableAllBtn();
                $c.gus.cfEnableObjects([btn_save, chk_transhipYn, btn_rowAdd, btn_rowDelete, btn_rowCancel]);
                $c.gus.cfDisableObjects([btn_update, btn_delete, btn_confirmOdr]);

                scwin.f_setActiveImgPopUp("E");             //팝업버튼 활성화
                gr_cntrInfo.setReadOnly("grid", false);     //그리드 활성화
                lc_odrKndCd.setValue("C5");
                lc_odrKndCd.focus();

                scwin.mgntTrgtClntYn = 0; // 계약거래처 관리구분여부 초기화
                scwin.statusFlag = "C";     //수정등록 flag
                scwin.retrieveYn = "N";     //조회여부

            } else if (gubun2 == "ODRKNDCD") {//오더종류 변경되는 경우
                if (ds_cndCtrtNo.getTotalRow() > 0) ds_cndCtrtNo.removeAll();
                if (ds_ctrtNo.getTotalRow() > 0) ds_ctrtNo.removeAll();
                if (ds_reqClntNo.getTotalRow() > 0) ds_reqClntNo.removeAll();
                if (ds_bilgClntNo.getTotalRow() > 0) ds_bilgClntNo.removeAll();
                if (ds_cntrInfo.getTotalRow() > 0) ds_cntrInfo.removeAll();

                //총건수 세팅
                spn_totalRow.setValue(ds_cntrInfo.getTotalRow());

                //초기화
                $c.gus.cfInitObjects([tbl_odrInfoArea, scwin.hid_chkReterieve]);
                scwin.mgntTrgtClntYn = 0; // 계약거래처 관리구분여부 초기화
            }

            lc_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS);

            scwin.f_setDefaultValue();//기본정보세팅
            //scwin.f_setSellAndBilgDept();
            break;

        case "RETRIEVE": //조회모드
            odrDcsnYn = ds_odrInfo.getCellData(0, "odrDcsnYn");     //확정여부
            odrDelYn = ds_odrInfo.getCellData(0, "odrDelYn");      //삭제여부
            odrCompleteYn = ds_odrInfo.getCellData(0, "odrCompleteYn"); //오더완료여부
            autoOdrYn = ds_odrInfo.getCellData(0, "autoOdrYn");     //자동오더여부
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableAllBtn();
            $c.gus.cfDisableObjects([btn_save, btn_rowAdd, btn_rowDelete, btn_rowCancel, chk_transhipYn]);
            $c.gus.cfEnableObjects([btn_search, btn_clear, btn_update]);

            scwin.f_setActiveImgPopUp("D");         //팝업버튼 비활성화
            gr_cntrInfo.setReadOnly("grid", true);  //그리드 비활성화

            //확정버튼 control
            if (autoOdrYn == "1") { //자동오더인 경우 모두 비활성
                $c.gus.cfDisableBtnOnly([btn_update]);
            } else {
                if (odrDcsnYn != DsConstants.YN_YES) { // 오더가 확정되지 않은 경우
                    $c.gus.cfEnableObjects([btn_confirmOdr]);
                    $c.gus.cfEnableBtnOnly([btn_update]);
                } else { // 오더가 확정된 경우
                    $c.gus.cfDisableObjects([btn_confirmOdr]);
                    $c.gus.cfEnableBtnOnly([btn_update]);

                    if (odrCompleteYn == DsConstants.YN_YES) {
                        $c.gus.cfDisableBtnOnly([btn_update]);
                        $c.gus.cfDisableObjects([btn_tmlEdiIfno]);
                    }
                }
            }
            break;

        case "UPDATE": //수정모드
            $c.gus.cfDisableObjects([btn_confirmOdr]);
            scwin.odrKndCd = lc_odrKndCd.getValue();      //오더종류
            scwin.impExpClsCd = "D";
            let cntrInfoRows = ds_cntrInfo.getTotalRow();
            odrDcsnYn = ds_odrInfo.getCellData(0, "odrDcsnYn");     //확정여부
            odrDelYn = ds_odrInfo.getCellData(0, "odrDelYn");      //삭제여부
            odrCompleteYn = ds_odrInfo.getCellData(0, "odrCompleteYn"); //오더완료여부
            autoOdrYn = ds_odrInfo.getCellData(0, "autoOdrYn");     //자동오더여부

            $c.gus.cfEnableObjects([btn_delete, btn_save, btn_rowAdd, btn_rowDelete, btn_rowCancel, chk_transhipYn, rd_sellYn, ed_clntMgntNo]);
            gr_cntrInfo.setReadOnly("grid", false);
            scwin.statusFlag = "U";
            scwin.f_c5c6EnDisableSet();
            $c.gus.cfEnableObjects([txt_rmk, co_lc_liVanTermCd]);

            //실적 발생여부를 조회하여 수정항목을 설정
            let chkVal = await scwin.f_chkResultsConfirmation();
            if (!chkVal) {
                if ("4AA" != scwin.lobranCd) {
                    $c.gus.cfEnableObjects([ed_dptDtl, ed_onPicNm, ed_onPicTelNo, ed_lduldDtl, ed_lduldPicNm, ed_lduldPicTelNo, ed_arvDtl, ed_offPicNm, ed_offPicTelNo, txt_rmk, ed_alloccarPicId]);
                }
                else {
                    $c.gus.cfEnableObjects([ed_dptDtl, lc_time, ed_onPicTelNo, ed_lduldDtl, ed_lduldPicNm, ed_lduldPicTelNo, ed_arvDtl, ed_offPicNm, ed_offPicTelNo, txt_rmk, ed_alloccarPicId]);
                }

                $c.gus.cfEnableObjects([ed_dptWrkPlCd, ed_dptZip, ed_dptDtl, ed_arvWrkPlCd, ed_arvZip, ed_arvDtl, ica_wrkStDt, ed_wrkStHh, ica_wrkEndDt, ed_wrkEndHh, ed_sellLodeptCd, ed_bilgLodeptCd]);
                if (cbx_retrvStpYn.getValue() == "1") {
                    $c.gus.cfEnableObjects([ed_lduldWrkPlCd, ed_lduldZip, ed_lduldDtl, ed_lduldDt, ed_lduldHh]);
                }
            }

            break;
    }
}

//실적 발생여부를 확인
scwin.f_chkResultsConfirmation = async function () {
    for (let i = 0; i < ds_cntrInfo.getTotalRow(); i++) {
        if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo")))
            return true; // 실적이 존재하는 경우
        break;
    }

    return false;   // 실적이 존재하지 않는 경우
}

