}

//신규
scwin.f_create = async function () {
    scwin.f_set("INIT", "CREATE"); //신규모드

    //RPA 아이디  신규버튼 클릭 시 고정값 셋팅
    if ("811160" == scwin.userId) {
        /*
        오더종류 : [C5] ON-HIRE
        계약처 : 317034 청암물류 주식회사
        계약번호 : C1105000982(정희태:~20271231:KR) 
        청구처 : 317034 청암물류 주식회사
        요청처 : 317034 청암물류 주식회사
        매출부서 : 6C29 (DGT CY)
        청구부서 : 6A1 (부산관리/영업)
        매출/관련번호 : YES
        자가구분 : [JE]자가반출
        상차지 : 6P90 (DGT) (46767)
        하차지 : 6P90 (DGT) (46767)
        */

        lc_odrKndCd.setValue("C5");
        ed_ctrtClntNo.setValue("317034");
        await scwin.f_openCommonPopUp(1, 'CTRT', 'T', 'F', 'F');
        lc_ctrtNo.setValue("C1105000982");

        //계약번호 선택되면서 기본셋팅됨
        // 		ed_bilgClntNo.text = "317034";
        // 		ed_reqClntNo.text = "317034";

        ed_sellLodeptCd.setValue("6C29");
        await scwin.f_openCommonPopUp(2, 'SELL', 'T', 'F', 'F');
        ed_bilgLodeptCd.setValue("6A1");
        await scwin.f_openCommonPopUp(2, 'BILG', 'T', 'F', 'F');
        rd_sellYn.setValue("1");
        lc_selfClsCd.setValue("JE");
        ed_dptWrkPlCd.setValue("6P90");
        await scwin.f_openCommonPopUp(5, 'DPT', 'T', 'F', 'F');
        ed_arvWrkPlCd.setValue("6P90");
        await scwin.f_openCommonPopUp(5, 'ARV', 'T', 'F', 'F');
    }

    let v_odrKndCd = lc_odrKndCd.getValue();
    if (v_odrKndCd == "C5" || v_odrKndCd == "C6") {
        $c.gus.cfDisableObjects([ed_railroadDptWrkPlCd, btn_railroadDptWrkPlCd, ed_railroadArvWrkPlCd, btn_railroadArvWrkPlCd]);
    } else {
        $c.gus.cfEnableObjects([ed_railroadDptWrkPlCd, btn_railroadDptWrkPlCd, ed_railroadArvWrkPlCd, btn_railroadArvWrkPlCd]);
    }

    rd_sellYn.setValue("1");
    scwin.f_blControl("F");
}

//신규/수정 저장
scwin.f_save = async function () {
    if (cbx_retrvStpYn.getValue() == "1") {
        let v_lduldWrkPlCd = ds_odrInfo.getCellData(0, "lduldWrkPlCd");
        ds_odrInfo.setCellData(0, "lduldWrkPlCd", ds_odrInfo.getCellData(0, "dptWrkPlCd"));
        ds_odrInfo.setCellData(0, "dptWrkPlCd", v_lduldWrkPlCd);
    }

    //환적 체크값 세팅 황창기
    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) { //c7오더
        if (chk_transhipYn.getValue() == "1") ds_odrInfo.setCellData(0, "transhipYn", "1");
    } else {
        ds_odrInfo.setCellData(0, "transhipYn", "0");
    }

    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.f_sameYn()) {
        if ($c.gus.cfIsNull(ed_bookingNo.getValue().trim()) && $c.gus.cfIsNull(ed_blNo.getValue().trim())) {
            scwin.impExpClsCd = "D";
        }
        else if (!$c.gus.cfIsNull(ed_bookingNo.getValue().trim()) && !$c.gus.cfIsNull(ed_blNo.getValue().trim())) {
            $c.win.alert("BK/BL 중복 등록 불가합니다.");
            return;
        }
        else if ($c.gus.cfIsNull(ed_bookingNo.getValue().trim())) {
            scwin.impExpClsCd = "I";
        }
        else {
            scwin.impExpClsCd = "O";
        }
    }

    ds_odrInfo.setCellData(0, "impExpDomesticClsCd", scwin.impExpClsCd);
    if (scwin.statusFlag == "U") { //수정
        //alert('123');
        if ($c.data.isModified(ds_odrInfo) || $c.data.isModified(ds_cntrInfo)) {
            //f_setValueBeforeValidation(); //validation하기 전에 꼭 세팅되어야 할 값들을 세팅
            //ds_cntrInfo.UseChangeInfo = true;

            let cntrRows = ds_cntrInfo.getTotalRow();
            if ( //ds_cntrInfo.IsUpdated == true ||
                ds_odrInfo.getOriginalCellData(0, "dptWrkPlCd") != ds_odrInfo.getCellData(0, "dptWrkPlCd")
                || ds_odrInfo.getOriginalCellData(0, "arvWrkPlCd") != ds_odrInfo.getCellData(0, "arvWrkPlCd")
                || ds_odrInfo.getOriginalCellData(0, "lduldWrkPlCd") != ds_odrInfo.getCellData(0, "lduldWrkPlCd")
                || ds_odrInfo.getOriginalCellData(0, "railroadDptWrkPlCd") != ds_odrInfo.getCellData(0, "railroadDptWrkPlCd")
                || ds_odrInfo.getOriginalCellData(0, "railroadArvWrkPlCd") != ds_odrInfo.getCellData(0, "railroadArvWrkPlCd")
                || ds_odrInfo.getOriginalCellData(0, "wrkStDt") != ds_odrInfo.getCellData(0, "wrkStDt")
                || ds_odrInfo.getOriginalCellData(0, "wrkEndDt") != ds_odrInfo.getCellData(0, "wrkEndDt")
                || ds_odrInfo.getOriginalCellData(0, "lduldDt") != ds_odrInfo.getCellData(0, "lduldDt")) {
                let i;
                for (i = 0; i < cntrRows; i++) {
                    if (ds_cntrInfo.getRowStatus(i) == "R") {
                        ds_cntrInfo.setCellData(i, "arvWrkPlNm", "update");
                        ds_cntrInfo.modifyRowStatus(i, "U");
                    }
                }

                //2009.09.04 컨테이너정보의 수출신고번호필드에 값을 입력한다.
                ds_cntrInfo.setCellData(i, "expDeclarNo", ed_expDeclarNo.getValue());
            }

            if (lc_ctrtNo.getValue() === "") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약번호"]); //@은(는) 필수 입력 항목입니다
                return false;
            }

            let excpt = [];
            if(tr_vanTerm.getStyle("display") == "none") {
                excpt.push(co_lc_liVanTermCd);
            }
            let chkVal = await $c.gus.cfValidate([tbl_odrInfoArea, tbl_odrInfoArea2, gr_cntrInfo, ed_odrNo], excpt, true)
            if (chkVal) {
                chkVal = await scwin.f_duplicatedCntrNoCheck();
                if (!chkVal) {
                    return false;
                } //컨테이너번호 중복여부 체크

                let conf = await $c.win.confirm($c.gus.cfGetMsg(MSG_CM_CRM_001));
                if (conf) { //저장하시겠습니까? 
                    await scwin.f_setValueBeforeSave(); //저장하기전 데이터 세팅
                    scwin.f_updateByOdrKndCd(); //오더종류별 저장
                }
            }
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더"]); //@은(는) 변경된 사항이 없습니다.
        }
    } else if (scwin.statusFlag == "C") { //신규
        if ($c.data.isModified(ds_odrInfo)) {

            if (lc_ctrtNo.getValue() == "") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약번호"]); //@은(는) 필수 입력 항목입니다
                return false;
            }

            // C6 오더 WJS 라인인 경우 VANTERM 체크
            // C7 오더 vanterm 추가, 20140811 hurrah 
            if ((scwin.odrKndCd == DsConstants.ODR_KND_CD_OFF_HIRE_ODR
                || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR)
                && ed_lineCd.getValue().trim() == "WJS") {

                if ($c.util.isEmpty(co_lc_liVanTermCd.getValue())) {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["VANTERM"]); //@은(는) 필수 입력 항목입니다.
                    return false;
                }
            }

            let chkVal;
            let excpt = [];

            if(tr_vanTerm.getStyle("display") == "none") {
                excpt.push(co_lc_liVanTermCd);
            }

            if (tbl_c7Format.getStyle("display") == "none") {
                excpt.push(...[udc_lduldWrkPlCd, ed_lduldWrkPlCd, ed_lduldZip, ed_lduldDtl, ica_lduldDt, ed_lduldHh]);
                chkVal = await $c.gus.cfValidate([tbl_odrInfoArea, tbl_odrInfoArea2], excpt, true);
                if (!chkVal) return;
            } else {
                chkVal = await $c.gus.cfValidate([tbl_odrInfoArea, tbl_odrInfoArea2], excpt, true);
                if (!chkVal) return;
            }

            chkVal = await $c.gus.cfValidate([gr_cntrInfo], null, true);
            if (!chkVal) return;

            if (chkVal) {
                //컨테이너번호 중복여부 체크
                chkVal = await scwin.f_duplicatedCntrNoCheck();
                if (!chkVal) return false;

                // 상하차시간 체크
                chkVal = await scwin.f_chkBetweenTime();
                if (!chkVal) return false;

                let conf = await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_001));
                if (conf) {
                    //오더확정구분을 0으로 변경
                    ds_odrInfo.setCellData(0, "odrDcsnYn", "0");
                    scwin.f_setValueBeforeSave(); //저장하기전 데이터 세팅
                    scwin.f_registByOdrKndCd(); //오더종류별 저장
                }
            }
        } else {
            if ($c.data.isModified(ds_cntrInfo)) {

                let excpt = [];
                if(tr_vanTerm.getStyle("display") == "none") {
                    excpt.push(co_lc_liVanTermCd);
                }
                let chkVal = await $c.gus.cfValidate([tbl_odrInfoArea], excpt, true);
                if (chkVal) return;
            } else {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더"]); //@은(는) 변경된 사항이 없습니다.
            }
        }
    }
}

