    } else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR && scwin.f_sameYn()) {
        tr_vanTerm.hide();

        scwin.f_blControl("T");
        await scwin.f_beforeOpenCommonPopUpEd(ed_lineNm, ed_lineCd, 3, '', 'T', 'F');
    // C7 오더 venterm체크 추가, 2014.08.11 hurrah
    } else if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR
        && (ed_lineCd.getValue().trim() == "WJS" || ed_lineCd.getValue().trim() == "wjs")
        && (v_selfClsCd == "LI")
    ) {
        tr_vanTerm.show("");
        scwin.f_blControl("F");
        await scwin.f_beforeOpenCommonPopUpEd(ed_lineNm, ed_lineCd, 3, '', 'T', 'F');
    } else {
        tr_vanTerm.hide();
        scwin.f_blControl("F");
        await scwin.f_beforeOpenCommonPopUpEd(ed_lineNm, ed_lineCd, 3, '', 'T', 'F');
    }
};

